class Solution:
    def maxSumSubmatrix(self, matrix: List[List[int]], k: int) -> int:
        m, n = len(matrix), len(matrix[0])
        ans = -10**18
        for left in range(n):
            row = [0]*m
            for right in range(left, n):
                for i in range(m): row[i] += matrix[i][right]
                curr, prefixes = 0, [0]
                for x in row:
                    curr += x
                    idx = bisect.bisect_left(prefixes, curr - k)
                    if idx < len(prefixes): ans = max(ans, curr - prefixes[idx])
                    bisect.insort(prefixes, curr)
        return ans

