class Solution {
public:
    int maxSumSubmatrix(vector<vector<int>>& matrix, int k) {
        int m = matrix.size(), n = matrix[0].size(), ans = INT_MIN;
        for (int l = 0; l < n; l++) {
            vector<int> row(m, 0);
            for (int r = l; r < n; r++) {
                for (int i = 0; i < m; i++) row[i] += matrix[i][r];
                set<int> st; st.insert(0);
                int sum = 0;
                for (int x : row) {
                    sum += x;
                    auto it = st.lower_bound(sum - k);
                    if (it != st.end()) ans = max(ans, sum - *it);
                    st.insert(sum);
                }
            }
        }
        return ans;
    }
};

