int maxSumSubmatrix(int** matrix, int m, int* cs, int k) {
    int n=cs[0], ans=INT_MIN;
    for(int l=0;l<n;l++){
        int* row=calloc(m,sizeof(int));
        for(int r=l;r<n;r++){
            for(int i=0;i<m;i++) row[i]+=matrix[i][r];
            int sum=0; int* pref=malloc(100000*sizeof(int)); int ps=0; pref[ps++]=0;
            for(int i=0;i<m;i++){
                sum+=row[i];
                for(int j=0;j<ps;j++) if(sum-pref[j]<=k && sum-pref[j]>ans) ans=sum-pref[j];
                pref[ps++]=sum;
            }
            free(pref);
        }
        free(row);
    }
    return ans;
}
